-- Matching y enriquecimiento atómico
DO $$
DECLARE
  v_user_id uuid := 'f103da90-81d4-43a2-ad34-b33db8b9c369';
  v_enriched int := 0;
  v_skipped_ambiguous int := 0;
  v_unmatched int := 0;
  v_ghosts_merged int := 0;
  rec record;
  matched_id uuid;
  match_count int;
  collide_id uuid;
BEGIN
  -- Tabla de log temporal
  CREATE TEMP TABLE _import_log (
    in_name text, status text, contact_id uuid, db_name text, detail text
  ) ON COMMIT DROP;

  FOR rec IN SELECT * FROM public._tmp_mac_import LOOP
    matched_id := NULL;

    -- 1) match por teléfono (wa_id o phone_numbers) — siempre prioritario
    SELECT id INTO matched_id
    FROM public.people_contacts
    WHERE user_id = v_user_id
      AND (wa_id = ANY(rec.phones) OR phone_numbers && rec.phones)
    LIMIT 1;

    IF matched_id IS NULL THEN
      -- 2) match por nombre normalizado, solo si es ÚNICO
      SELECT COUNT(*) INTO match_count
      FROM public.people_contacts
      WHERE user_id = v_user_id
        AND lower(unaccent(name)) = rec.name_norm;

      IF match_count = 1 THEN
        SELECT id INTO matched_id
        FROM public.people_contacts
        WHERE user_id = v_user_id
          AND lower(unaccent(name)) = rec.name_norm
        LIMIT 1;
      ELSIF match_count > 1 THEN
        -- ambiguo: hay varios contactos con ese nombre, intentar el que NO tenga wa_id (vacío)
        SELECT id INTO matched_id
        FROM public.people_contacts
        WHERE user_id = v_user_id
          AND lower(unaccent(name)) = rec.name_norm
          AND wa_id IS NULL
        LIMIT 1;

        IF matched_id IS NULL THEN
          v_skipped_ambiguous := v_skipped_ambiguous + 1;
          INSERT INTO _import_log VALUES (rec.name,'ambiguous',NULL,NULL,'multiple matches all with wa_id');
          CONTINUE;
        END IF;
      END IF;
    END IF;

    IF matched_id IS NULL THEN
      v_unmatched := v_unmatched + 1;
      INSERT INTO _import_log VALUES (rec.name,'unmatched',NULL,NULL,NULL);
      CONTINUE;
    END IF;

    -- Resolver colisión: ¿algún OTRO contacto del usuario ya tiene ese desired_wa?
    SELECT id INTO collide_id
    FROM public.people_contacts
    WHERE user_id = v_user_id
      AND wa_id = rec.desired_wa
      AND id <> matched_id
    LIMIT 1;

    IF collide_id IS NOT NULL THEN
      -- Mover mensajes del fantasma al contacto real
      UPDATE public.contact_messages
      SET contact_id = matched_id
      WHERE user_id = v_user_id AND contact_id = collide_id;

      DELETE FROM public.contact_headlines WHERE contact_id = collide_id;
      DELETE FROM public.people_contacts WHERE id = collide_id AND user_id = v_user_id;
      v_ghosts_merged := v_ghosts_merged + 1;
    END IF;

    -- Update: setear wa_id si vacío, mergear phone_numbers
    UPDATE public.people_contacts pc
    SET 
      wa_id = COALESCE(pc.wa_id, rec.desired_wa),
      phone_numbers = (
        SELECT ARRAY(SELECT DISTINCT unnest(COALESCE(pc.phone_numbers, ARRAY[]::text[]) || rec.phones))
      ),
      updated_at = now()
    WHERE pc.id = matched_id;

    -- Limpiar headlines para forzar regeneración
    DELETE FROM public.contact_headlines WHERE contact_id = matched_id;

    v_enriched := v_enriched + 1;
    INSERT INTO _import_log VALUES (
      rec.name,'enriched',matched_id,
      (SELECT name FROM public.people_contacts WHERE id=matched_id),
      array_to_string(rec.phones,',')
    );
  END LOOP;

  RAISE NOTICE 'Enriched: %, Ambiguous skipped: %, Unmatched: %, Ghosts merged: %',
    v_enriched, v_skipped_ambiguous, v_unmatched, v_ghosts_merged;

  -- Persistir resumen en una tabla regular para inspeccionarlo después
  CREATE TABLE IF NOT EXISTS public._tmp_mac_import_log (
    in_name text, status text, contact_id uuid, db_name text, detail text, run_at timestamptz default now()
  );
  TRUNCATE public._tmp_mac_import_log;
  INSERT INTO public._tmp_mac_import_log (in_name,status,contact_id,db_name,detail)
  SELECT in_name,status,contact_id,db_name,detail FROM _import_log;
END $$;

-- Mantener _tmp_mac_import por ahora para inspección posterior; se borra en una segunda migration.
